module blinky #(
    parameter integer DIV = (27000000 / 2)
) (
    input sys_clk,
    output logic led
);

always_ff @(posedge sys_clk) begin
    if (sys_reset) begin
        blink_counter <= 0;
    end else if (blink_counter < (DIV - 1)) begin
        blink_counter <= blink_counter + 1;
    end else begin
        blink_counter <= 0;
    end
end
